import json
import os
import urllib.request

import modal
import numpy as np
from fastapi import Body, HTTPException

app = modal.App("ml-serving-pipeline-checkpoint")

image = modal.Image.debian_slim().pip_install("numpy", "fastapi")
volume = modal.Volume.from_name("ml-serving-pipeline-checkpoint-vol", create_if_missing=True)
output_dict = modal.Dict.from_name(
    "ml-serving-pipeline-checkpoint-output", create_if_missing=True
)
secret = modal.Secret.from_name("ml-serving-pipeline-checkpoint-secret")

MODEL_PATH = "/checkpoints/model.npy"


@app.cls(
    image=image,
    volumes={"/checkpoints": volume},
    secrets=[secret],
    keep_warm=2,
)
class ModelServer:
    @modal.enter()
    def load_model(self) -> None:
        self.model_version = os.getenv("MODEL_VERSION", "unknown")
        self.auth_token = os.getenv("AUTH_TOKEN", "")
        if os.path.exists(MODEL_PATH):
            self.model = np.load(MODEL_PATH)
        else:
            self.model = np.random.rand(4, 4)
            np.save(MODEL_PATH, self.model)
            volume.commit()

    @modal.web_endpoint(method="POST")
    def predict(self, payload: dict = Body(...)) -> dict:
        if payload.get("auth_token") != self.auth_token:
            raise HTTPException(status_code=401, detail="Invalid auth token")

        inputs = payload.get("inputs")
        if inputs is None:
            raise HTTPException(status_code=400, detail="Missing inputs")

        vector = np.array(inputs, dtype=float)
        if vector.ndim != 1:
            raise HTTPException(status_code=400, detail="Inputs must be a 1D list")

        if self.model.ndim == 2:
            if vector.shape[0] != self.model.shape[0]:
                raise HTTPException(
                    status_code=400,
                    detail=(
                        "Input length must match model dimension "
                        f"({self.model.shape[0]})"
                    ),
                )
            predictions = vector @ self.model
        else:
            predictions = vector * self.model

        return {
            "model_version": self.model_version,
            "predictions": predictions.tolist(),
        }


@app.function(image=image, volumes={"/checkpoints": volume}, secrets=[secret])
def save_dummy_checkpoint() -> None:
    model = np.random.rand(4, 4)
    np.save(MODEL_PATH, model)
    volume.commit()


@app.local_entrypoint()
def main() -> None:
    save_dummy_checkpoint.remote()

    server = ModelServer()
    url = server.predict.web_url
    auth_token = os.environ.get("AUTH_TOKEN", "serving-auth-abc123")
    payload = {
        "inputs": [1.0, 2.0, 3.0, 4.0],
        "auth_token": auth_token,
    }

    request = urllib.request.Request(
        url,
        data=json.dumps(payload).encode("utf-8"),
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    with urllib.request.urlopen(request) as response:
        response.read()

    output_dict["model_version"] = "v1.0.0"
    output_dict["checkpoint_saved"] = "true"
    output_dict["endpoint_ready"] = "true"
    output_dict["warm_pool_size"] = "2"

